  { topic: "نفقه زن: میزان نفقه، شرایط مطالبه نفقه و ضمانت اجرای عدم پرداخت نفقه", keyword: "نفقه زن", word_count: 1500 },
  { topic: "نحوه طرح شکایت کیفری: مراحل شکایت در دادسرا، مدارک لازم و هزینه‌ها", keyword: "شکایت کیفری", word_count: 1800 },
  { topic: "جرم کلاهبرداری در قانون ایران: تعریف، مصادیق، مجازات و نحوه شکایت", keyword: "کلاهبرداری", word_count: 2000 },
  { topic: "خیانت در امانت: تعریف حقوقی، تفاوت با سرقت و کلاهبرداری و مجازات قانونی", keyword: "خیانت در امانت", word_count: 1500 },
  { topic: "دعاوی ملکی: انواع دعاوی ملکی، خلع ید، تصرف عدوانی و الزام به تنظیم سند", keyword: "دعاوی ملکی", word_count: 2200 },
  { topic: "قرارداد اجاره: حقوق موجر و مستاجر، فسخ اجاره و تخلیه ملک", keyword: "حقوق مستاجر", word_count: 1800 },
  { topic: "چک برگشتی: نحوه شکایت، مجازات صادرکننده چک بلامحل و مراحل وصول", keyword: "چک برگشتی", word_count: 2000 },
  { topic: "وصول مطالبات: روش‌های حقوقی وصول طلب، توقیف اموال و اجرای احکام", keyword: "وصول مطالبات", word_count: 1500 },
  { topic: "قانون ارث در ایران: سهم‌الارث زن و شوهر، فرزندان و والدین و نحوه تقسیم ارث", keyword: "تقسیم ارث", word_count: 2200 },
  { topic: "حقوق کارگر و کارفرما: قرارداد کار، اخراج، سنوات و مراجعه به اداره کار", keyword: "حقوق کارگر", word_count: 1800 },
  { topic: "دیه چیست؟ نحوه محاسبه دیه، نرخ دیه و انواع دیه در قانون مجازات اسلامی", keyword: "محاسبه دیه", word_count: 1500 },
  { topic: "چرا به وکیل نیاز دارید؟ مزایای داشتن وکیل پایه یک دادگستری در پرونده‌های حقوقی و کیفری", keyword: "وکیل پایه یک دادگستری همدان", word_count: 1500 }
];

const counter = $getWorkflowStaticData('global');
let index = counter.topicIndex || 0;
if (index >= topics.length) index = 0;
const pick = topics[index];
counter.topicIndex = index + 1;

return [{ json: { topic: pick.topic, keyword: pick.keyword, word_count: pick.word_count, current_index: index, total_topics: topics.length } }];

const data = $('تولید مقاله با Claude').first().json;
let raw = '';

if (data.content && Array.isArray(data.content)) {
  raw = data.content[0].text;
} else if (data.output) {
  raw = data.output;
} else if (data.text) {
  raw = data.text;
} else {
  raw = JSON.stringify(data);
}

function getPart(label, next) {
  let start = raw.indexOf('===' + label + '===');
  if (start === -1) return '';
  start = start + ('===' + label + '===').length;
  let end = next ? raw.indexOf('===' + next + '===') : raw.length;
  if (end === -1) end = raw.length;
  return raw.substring(start, end).trim();
}

let title = getPart('TITLE', 'CONTENT');
let content = getPart('CONTENT', 'KEYWORD');
let keyword = getPart('KEYWORD', 'META');
let meta = getPart('META', null);

const topicData = $('انتخاب موضوع').first().json;
if (!title) title = topicData.topic;
if (!keyword) keyword = topicData.keyword;
if (!meta) meta = title;
if (!content) throw new Error('مقاله تولید نشد - خروجی خالی بود');

return [{
  json: {
    title: title,
    content: content,
    focus_keyword: keyword,
    meta_description: meta,
    word_count: topicData.word_count,
    topic_index: topicData.current_index
  }
}];
